parameters.functionCode:
// Shape incoming Alertmanager payload into the fields we need downstream.
// Filters + rules here:
//   - severity != 'critical' -> skip (Slack still fires from Alertmanager)
//   - dedup key = sha256(groupKey) truncated to 16 chars, prefixed 'gw-'
//   - firing -> create/update; resolved -> add 'auto-resolved' note (don't
//     close; operators manually close so stale resolved-then-fires aren't
//     hidden behind a wrongly-closed ticket).
//
// Expected Alertmanager webhook shape:
//   { status, groupKey, commonLabels{severity,alertname,...}, commonAnnotations{summary,description}, alerts:[...] }
const crypto = require('crypto');
const body = $input.item.json;

const zammadUrl   = ($env.ZAMMAD_URL || '').replace(/\/+$/, '');
const zammadToken = $env.ZAMMAD_API_TOKEN;
if (!zammadUrl || !zammadToken || zammadToken === 'CHANGE_ME') {
  throw new Error('ZAMMAD_URL / ZAMMAD_API_TOKEN not configured');
}

const status    = (body.status || '').toLowerCase();          // firing | resolved
const labels    = body.commonLabels || {};
const annot     = body.commonAnnotations || {};
const severity  = (labels.severity || '').toLowerCase();
const alertname = labels.alertname || body.groupLabels?.alertname || 'unknown';

if (severity !== 'critical') {
  return [{ json: { skip: true, reason: `severity=${severity||'unset'} not critical`, status_code: 204 } };
}

const dedupKey = 'gw-' + crypto.createHash('sha256')
  .update(body.groupKey || `${alertname}|${JSON.stringify(labels)}`)
  .digest('hex').slice(0, 16);

const lines = [];
lines.push(`Gateway status: ${status.toUpperCase()}`);
lines.push(`Alert: ${alertname}`);
lines.push(`Severity: ${severity}`);
if (annot.summary)     lines.push('', 'Summary:',     annot.summary);
if (annot.description) lines.push('', 'Description:', annot.description);
lines.push('', `Alerts in group (${(body.alerts||[]).length}):`);
for (const a of (body.alerts || []).slice(0, 20)) {
  const inst = a.labels?.instance || a.labels?.service || a.labels?.job || '?';
  lines.push(`  - [${a.status||'?'}] ${inst}  ${a.annotations?.summary || ''}  (since ${a.startsAt})`);
  if (a.generatorURL) lines.push(`      ${a.generatorURL}`);
}

return {
  json: {
    skip:        false,
    status,
    alertname,
    severity,
    dedup_key:   dedupKey,
    title:       `[${alertname}] ${annot.summary || 'gateway alert'}`.slice(0, 200),
    article_subject: (annot.summary || alertname).slice(0, 200),
    article_body:    lines.join('\n'),
    zammad_url:     zammadUrl,
    zammad_token:   zammadToken,
    zammad_group:   $env.ZAMMAD_GROUP    || 'Users',
    zammad_customer:$env.ZAMMAD_CUSTOMER || 'info@goarmstrong.com',
    raw:            body
  }
};

// Zammad's /tickets/search returns either an array or an object with
// tickets_count + assets.Ticket. Normalize to a single ticket_id or null.
const resp = $input.item.json;
const ctx  = $('Parse + Filter').item.json;
let existing_id = null;
if (Array.isArray(resp) && resp.length) {
  existing_id = resp[0]?.id || resp[0]?.ticket_id || null;
} else if (resp && resp.tickets && Array.isArray(resp.tickets) && resp.tickets.length) {
  existing_id = resp.tickets[0];
} else if (resp && resp.assets && resp.assets.Ticket) {
  const ids = Object.keys(resp.assets.Ticket);
  if (ids.length) existing_id = parseInt(ids[0], 10);
}
return [{ json: { ...ctx, existing_id } };

parameters.jsonBody:
={{ JSON.stringify({
  ticket_id: $json.existing_id,
  subject:   ($json.status === 'resolved' ? '[auto-resolved] ' : '[re-fire] ') + $json.article_subject,
  body:      $json.article_body,
  type:      'note',
  internal:  false
}) }}

={{ JSON.stringify({
  title:      $json.title,
  group:      $json.zammad_group,
  customer:   $json.zammad_customer,
  state:      'new',
  priority:   '3 high',
  external_id:$json.dedup_key,
  article: { subject: $json.article_subject, body: $json.article_body, type: 'note', internal: false }
}) }}

