const err = $input.item.json;
return [{ json: {
  workflow: 'alertmanager-to-zammad',
  error:   err.message || err.error || 'unknown',
  status:  err.status || err.statusCode || 500,
  raw:     err,
  timestamp: new Date().toISOString()
}}];
